add_action('wp_footer', function () {
?>
<script>
document.addEventListener("DOMContentLoaded", function () {

  // Select all scrollable sections and tab links
  const sections = document.querySelectorAll(".scroll-section");
  const tabs = document.querySelectorAll(".tab-link a");

  /* Determines which section is closest to the viewport top and activates the corresponding tab link */
  function activateTab() {
    let closestSection = null;
    let closestDistance = Infinity;

    sections.forEach((section) => {
      const rect = section.getBoundingClientRect();
      const distance = Math.abs(rect.top - 150); // offset from top for better UX

      if (distance < closestDistance) {
        closestDistance = distance;
        closestSection = section;
      }
    });

    // Exit if no section is found
    if (!closestSection) return;

    const id = closestSection.id;

    // Update active state on tabs
    tabs.forEach((tab) => {
      tab.classList.remove("active");

      const href = tab.getAttribute("href");

      // Match tab link to section ID
      if (href && href.includes("#" + id)) {
        tab.classList.add("active");
      }
    });
  }

  // Update active tab on scroll
  window.addEventListener("scroll", activateTab);

  // Run once on page load
  activateTab();

  /* Smooth scrolling behavior for tab clicks */
  tabs.forEach(link => {
    link.addEventListener('click', function(e) {
      e.preventDefault();

      const targetId = this.getAttribute('href').split('#')[1];
      const target = document.getElementById(targetId);

      // Exit if target section does not exist
      if (!target) return;

      const offset = 120; // Adjust for sticky header height

      // Calculate final scroll position
      const top = target.getBoundingClientRect().top + window.scrollY - offset;

      // Scroll smoothly to target
      window.scrollTo({
        top: top,
        behavior: 'smooth'
      });
    });
  });

});
</script>
