add_action('wp_ajax_save_user_item', 'save_user_item');

function save_user_item() {

    // Ensure only logged-in users can save/remove items
    if (!is_user_logged_in()) {
        wp_send_json_error(['message' => 'Not logged in']);
    }

    $user_id = get_current_user_id();

    // Get existing bookmarks from user meta (fallback to empty array if none exist)
    $bookmarks = get_user_meta($user_id, 'saved_bookmarks', true);
    if (!is_array($bookmarks)) $bookmarks = [];

    // Get incoming AJAX data
    $post_id = isset($_POST['id']) ? (int) $_POST['id'] : 0;
    $type    = isset($_POST['type']) ? sanitize_text_field($_POST['type']) : '';
    $group   = isset($_POST['group']) ? sanitize_text_field($_POST['group']) : '';

    // Validate required data
    if (!$post_id || !$type) {
        wp_send_json_error(['message' => 'Missing data']);
    }

    // Default grouping if none is provided
    if (empty($group)) {
        $group = 'content';
    }

    // ---------------------------------------------------------
    // Check if item already exists in bookmarks
    // We match BOTH ID and type to avoid cross-page conflicts
    // ---------------------------------------------------------
    $exists_index = false;

    foreach ($bookmarks as $index => $item) {
        if (
            isset($item['id'], $item['type']) &&
            (int)$item['id'] === $post_id &&
            $item['type'] === $type
        ) {
            $exists_index = $index;
            break;
        }
    }

    // ---------------------------------------------------------
    // Toggle logic:
    // If exists → remove it
    // If not → add it
    // ---------------------------------------------------------
    if ($exists_index !== false) {
        unset($bookmarks[$exists_index]);

        // Re-index array to keep it clean
        $bookmarks = array_values($bookmarks);

        $status = 'removed';
    } else {
        $bookmarks[] = [
            'id'    => $post_id,
            'type'  => $type,
            'group' => $group
        ];

        $status = 'added';
    }

    // Save updated bookmarks back to user meta
    update_user_meta($user_id, 'saved_bookmarks', $bookmarks);

    // Return updated state to frontend
    wp_send_json_success([
        'status'    => $status,
        'bookmarks' => $bookmarks
    ]);
}

add_shortcode('user_saved', function($atts) {

    // ---------------------------------------------------------
    // Shortcode attributes (default: content bookmarks)
    // ---------------------------------------------------------
    $atts = shortcode_atts([
        'type' => 'content'
    ], $atts);

    $type    = $atts['type'];
    $user_id = get_current_user_id();

    // Get all saved bookmarks for the current user
    $bookmarks = get_user_meta($user_id, 'saved_bookmarks', true);

    if (!is_array($bookmarks)) {
        $bookmarks = [];
    }

    // ---------------------------------------------------------
    // Filter bookmarks by selected type (e.g. content / script)
    // ---------------------------------------------------------
    $filtered = array_filter($bookmarks, function($item) use ($type) {
        return isset($item['type']) &&
               $item['type'] === $type;
    });

    // Extract only post IDs for WP_Query
    $ids = array_map('intval', array_column($filtered, 'id'));

    // If nothing saved, show empty state early
    if (empty($ids)) {
        return '<p>No saved items yet.</p>';
    }

    // ---------------------------------------------------------
    // Map bookmark types to WordPress post types
    // ---------------------------------------------------------
    $post_type_map = [
        'content' => ['destination', 'knowledge', 'guide_topic'],
        'script'  => ['script']
    ];

    $post_types = $post_type_map[$type] ?? ['post'];

    // Query all saved posts based on stored IDs
    $query = new WP_Query([
        'post_type'      => $post_types,
        'post__in'       => $ids,
        'orderby'        => 'post__in', // keep original saved order
        'posts_per_page' => -1,
        'post_status'    => 'publish'
    ]);

    ob_start();

    // ---------------------------------------------------------
    // Render saved items grid
    // ---------------------------------------------------------
    if ($query->have_posts()) {

        echo '<div class="saved-grid">';

        while ($query->have_posts()) {
            $query->the_post();

            $post_id = get_the_ID();

            // Get category name (fallback to post type if none exists)
            $categories = get_the_category();
            $category_name = !empty($categories)
                ? $categories[0]->name
                : get_post_type();

            // -----------------------------------------------------
            // Find stored group for this specific bookmark
            // -----------------------------------------------------
            $group = 'content';

            foreach ($bookmarks as $b) {
                if (
                    isset($b['id'], $b['type'], $b['group']) &&
                    (int)$b['id'] === $post_id &&
                    $b['type'] === $type
                ) {
                    $group = $b['group'];
                    break;
                }
            }

            // Card wrapper with metadata for JS interactions
            echo '<div class="saved-card"
                    data-id="' . $post_id . '"
                    data-type="' . esc_attr($type) . '"
                    data-group="' . esc_attr($group) . '">';

                // -------------------------------------------------
                // OPTIONAL: selection checkbox (for scripts UI)
                // NOTE: assumes $script_id exists in your context
                // -------------------------------------------------
                echo '<label class="script-select-box">
                        <input type="checkbox" class="js-select-script" data-id="'.$script_id.'">
                      </label>';

                // Featured image
                echo '<div class="card-image">';
                    echo get_the_post_thumbnail($post_id, 'medium');
                echo '</div>';

                // -------------------------------------------------
                // Check if current item is saved (for heart state)
                // -------------------------------------------------
                $is_saved = false;

                foreach ($bookmarks as $b) {
                    if (
                        isset($b['id'], $b['type']) &&
                        (int)$b['id'] === $post_id &&
                        $b['type'] === $type
                    ) {
                        $is_saved = true;
                        break;
                    }
                }

                // Heart icon (filled if saved, empty if not)
                echo '<div class="card-heart '.($is_saved ? 'saved' : '').'"
                        data-id="'.$post_id.'"
                        data-type="'.esc_attr($type).'">'
                        .($is_saved ? '♥' : '♡').'
                      </div>';

                // Title + meta information
                echo '<div class="card-content">';
                    echo '<h3>' . get_the_title() . '</h3>';
                    echo '<div class="card-meta">' . esc_html($category_name) . '</div>';
                echo '</div>';

            echo '</div>'; // saved-card
        }

        echo '</div>'; // saved-grid

    } else {
        echo '<p>No posts found.</p>';
    }

    wp_reset_postdata();

    return ob_get_clean();
});

function my_scripts_query($query) {
    if (!is_admin() && $query->is_main_query() && is_page('scripts')) {

        $query->set('post_type', 'scripts');
        $query->set('author', get_current_user_id());

        $query->set('meta_query', [
            [
                'key'     => 'visibility',
                'value'   => 'private',
                'compare' => '='
            ]
        ]);
    }
}
add_action('pre_get_posts', 'my_scripts_query');

