add_action('wp_ajax_share_script', function () {

    if (!is_user_logged_in()) {
        wp_send_json_error(['message' => 'Not logged in'], 401);
    }

    $script_id = intval($_POST['script_id'] ?? 0);
    $user_id   = intval($_POST['user_id'] ?? 0);

    if (!$script_id || !$user_id) {
        wp_send_json_error(['message' => 'Missing data'], 400);
    }

    // SECURITY CHECK
    $post = get_post($script_id);

    if (!$post || $post->post_type !== 'script') {
        wp_send_json_error(['message' => 'Invalid script'], 400);
    }

    if ((int)$post->post_author !== get_current_user_id()) {
        wp_send_json_error(['message' => 'Not allowed'], 403);
    }

    // GET DATA
    $shared = get_post_meta($script_id, '_script_shared_with', true);
    if (!is_array($shared)) $shared = [];

    $shared_by = get_post_meta($script_id, '_script_shared_by', true);
    if (!is_array($shared_by)) $shared_by = [];

    $shared = array_map('intval', $shared);

    // TOGGLE LOGIC (FIXED)
    if (in_array($user_id, $shared, true)) {

        $shared = array_values(array_diff($shared, [$user_id]));
        unset($shared_by[$user_id]);

        $status = 'removed';

    } else {

        $shared[] = $user_id;

        $shared_by[$user_id] = [
            'sender_id' => get_current_user_id(),
            'time'      => time()
        ];

        $status = 'added';
    }

    update_post_meta($script_id, '_script_shared_with', $shared);
    update_post_meta($script_id, '_script_shared_by', $shared_by);

	if ($status === 'added') {

    $sender = wp_get_current_user();
    $script_title = get_the_title($script_id);

    // only notify the user being added (not everyone)
    create_user_notification(
        $user_id,
        $sender->display_name . ' shared "' . $script_title . '" with you',
        'script_share',
        $script_id
    );
}

    wp_send_json_success([
        'status' => $status
    ]);
});


