// MY SCRIPTS (ONLY CREATED BY ME)
function get_my_scripts_for_user($user_id) {

    return new WP_Query([
        'post_type'      => 'script',
        'posts_per_page' => -1,
        'author'         => $user_id
    ]);
}


// SHARED SCRIPTS (SENT TO ME BY OTHERS)
function get_shared_scripts_for_user($user_id) {

    return new WP_Query([
        'post_type'      => 'script',
        'posts_per_page' => -1,
        'author__not_in' => [$user_id],
        'meta_query'     => [
            [
                'key'     => '_script_shared_with',
                'compare' => 'EXISTS'
            ]
        ]
    ]);
}


// CHECK BOOKMARK STATE (GROUP-AWARE)
function is_script_saved($user_id, $script_id, $group) {

    $bookmarks = get_user_meta($user_id, 'saved_bookmarks', true);
    if (!is_array($bookmarks)) return false;

    foreach ($bookmarks as $item) {

        if (
            isset($item['id'], $item['type'], $item['group']) &&
            (int)$item['id'] === (int)$script_id &&
            $item['type'] === 'script' &&
            $item['group'] === $group
        ) {
            return true;
        }
    }

    return false;
}


