    $query = get_shared_scripts_for_user($user_id);

    $active_folder = isset($_GET['folder'])
        ? sanitize_text_field($_GET['folder'])
        : '';

    ob_start();

    echo '<div class="saved-grid">';

    echo "<!-- ACTIVE FOLDER: " . esc_html($active_folder) . " -->";

    $has_results = false;

    while ($query->have_posts()) {
        $query->the_post();

        $script_id = get_the_ID();

        $is_saved = is_script_saved($user_id, $script_id, 'shared');

        if ($type === 'saved' && !$is_saved) continue;
        if ($type === 'all' && $is_saved) continue;

        $folder = get_post_meta($script_id, '_script_folder', true);
        $folder = (string) $folder;

        if ($active_folder && $folder !== $active_folder) {
            continue;
        }

        $has_results = true;

        echo '<div class="saved-card"
            data-id="' . esc_attr($script_id) . '"
            data-folder="' . esc_attr($folder) . '"
            data-type="script"
            data-group="shared">';

        echo '<label class="script-select-box">
                <input type="checkbox" class="js-select-script" data-id="' . esc_attr($script_id) . '">
              </label>';

        the_post_thumbnail('medium');

        echo '<div class="card-heart ' . ($is_saved ? 'saved' : '') . '"
                data-id="' . esc_attr($script_id) . '"
                data-type="script">'
                . ($is_saved ? '♥' : '♡') .
             '</div>';

        echo '<h3>' . esc_html(get_the_title()) . '</h3>';
        echo '<div>Shared Script</div>';

        $shared_by = get_post_meta($script_id, '_script_shared_by', true);

        if (is_array($shared_by) && isset($shared_by[$user_id])) {

            $data = $shared_by[$user_id];

            if (!empty($data['sender_id'])) {
                $sender = get_userdata($data['sender_id']);

                if ($sender) {
                    echo '<div class="shared-by">Shared by: ' . esc_html($sender->display_name) . '</div>';
                }
            }

            if (!empty($data['time'])) {
                echo '<div class="shared-time">Shared on: ' . date('d M Y, H:i', $data['time']) . '</div>';
            }
        }

        echo '</div>';
    }

    echo '</div>';

    if (!$has_results) {
        echo '<div class="empty-state">No scripts in this folder.</div>';
    }

    wp_reset_postdata();

    return ob_get_clean();
}
