add_filter('query_loop_block_query_vars', function($query_vars, $block) {

    // Only affect your Destinations Query Loop
    if (!empty($block->context['query']['postType']) &&
        $block->context['query']['postType'] === 'destination') {

        if (!empty($_GET['orderby'])) {

            switch ($_GET['orderby']) {

                case 'title':
                    $query_vars['orderby'] = 'title';
                    $query_vars['order'] = $_GET['order'] ?? 'asc';
                    break;

                case 'date':
                    $query_vars['orderby'] = 'date';
                    $query_vars['order'] = $_GET['order'] ?? 'desc';
                    break;
            }
        }
    }

    return $query_vars;

}, 10, 2);

