add_filter('login_redirect', function ($redirect_to, $request, $user) {

    // ❌ LOGIN FAILED
    if (!is_object($user) || is_wp_error($user) || !isset($user->ID)) {
        return home_url('/login/?login=failed');
    }

    $user_id = $user->ID;

    // 🧭 CHECK ONBOARDING
    $done = get_user_meta($user_id, 'onboarding_done', true);

    if (!$done) {
        return home_url('/onboarding/?login=success');
    }

    // ✅ SUCCESSFUL LOGIN
    return home_url('/?login=success');

