// 🔁 HANDLE RESET REQUEST
// =====================================
add_action('init', function () {

    if (!isset($_POST['reset_password_submit'])) return;

    $login = sanitize_text_field($_POST['user_login']);

    // ❌ EMPTY INPUT
    if (empty($login)) {
        wp_redirect(home_url('/forgot-password/?reset=empty'));
        exit;
    }

    // Find user by email or username
    $user = get_user_by('email', $login);

    if (!$user) {
        $user = get_user_by('login', $login);
    }

    // ❌ USER NOT FOUND
    if (!$user) {
        wp_redirect(home_url('/forgot-password/?reset=notfound'));
        exit;
    }

    // ✅ SEND RESET EMAIL
    retrieve_password($user->user_login);

    wp_redirect(home_url('/forgot-password/?reset=success'));
    exit;
});

