	/* =========================
   RENAME FOLDER
========================= */
document.addEventListener('click', function (e) {

    const btn = e.target.closest('.js-rename-folder');
    if (!btn) return;

    const folderId = btn.dataset.id;
    const wrapper = btn.closest('.folder-card-wrapper');

    const nameEl = wrapper.querySelector('.folder-name');
    if (!nameEl) return;

    // prevent double edit
    if (wrapper.querySelector('.folder-rename-input')) return;

    const currentName = nameEl.textContent;

    const input = document.createElement('input');
    input.className = 'folder-rename-input';
    input.value = currentName;

    nameEl.replaceWith(input);
    input.focus();

    // save function
    const save = () => {
        const newName = input.value.trim();
        if (!newName) return;

        fetch('/wp-admin/admin-ajax.php', {
            method: 'POST',
            headers: {'Content-Type': 'application/x-www-form-urlencoded'},
            body: new URLSearchParams({
                action: 'rename_script_folder',
                folder_id: folderId,
                name: newName
            })
        })
        .then(r => r.json())
        .then(res => {

            if (!res.success) return;

            const span = document.createElement('span');
            span.className = 'folder-name';
            span.textContent = newName;

            input.replaceWith(span);

            window.existingFolders = window.existingFolders.map(f =>
                f.id === folderId ? { ...f, name: newName } : f
            );

            renderMoveFolders(window.existingFolders);
        });
    };

    input.addEventListener('keydown', function (ev) {
        if (ev.key === 'Enter') save();
        if (ev.key === 'Escape') {
            const span = document.createElement('span');
            span.className = 'folder-name';
            span.textContent = currentName;
            input.replaceWith(span);
        }
    });

    input.addEventListener('blur', save);
});
	 // =========================
    // HANDLE CONFIRM / CANCEL
    // =========================

	document.addEventListener('click', function (e) {

    const yes = e.target.closest('.confirm-delete');
    if (!yes) return;

    const folderId = yes.dataset.id;

    fetch('/wp-admin/admin-ajax.php', {
        method: 'POST',
        headers: {'Content-Type': 'application/x-www-form-urlencoded'},
        body: new URLSearchParams({
            action: 'delete_script_folder',
            folder_id: folderId
        })
    })
    .then(r => r.json())
    .then(res => {

        if (!res.success) return;

        document.querySelector(`.folder-card-wrapper .js-delete-folder[data-id="${folderId}"]`)
            ?.closest('.folder-card-wrapper')
            ?.remove();

        window.existingFolders =
            window.existingFolders.filter(f => f.id != folderId);
    });
});

document.addEventListener('click', function (e) {

    if (e.target.closest('.cancel-delete')) {

        const menu = e.target.closest('.folder-menu');

        // restore normal menu UI
        const wrapper = menu.closest('.folder-card-wrapper');
        const folderId = wrapper.querySelector('.js-delete-folder').dataset.id;

