add_action('wp_ajax_bulk_trash_scripts', 'bulk_trash_scripts_handler');

function bulk_trash_scripts_handler() {

    if (!is_user_logged_in()) {
        wp_send_json_error(['message' => 'Not logged in']);
    }

    $user_id = get_current_user_id();

    $ids = isset($_POST['ids'])
        ? json_decode(stripslashes($_POST['ids']), true)
        : [];

    if (!is_array($ids) || empty($ids)) {
        wp_send_json_error(['message' => 'No IDs received']);
    }

    $trashed = [];

    foreach ($ids as $id) {

        $id = (int) $id;

        $post = get_post($id);

        if (!$post || $post->post_type !== 'script') continue;
        if ((int)$post->post_author !== $user_id) continue;

        if (wp_trash_post($id)) {
            $trashed[] = $id;
        }
    }

    wp_send_json_success([
        'trashed' => $trashed
    ]);
}

