add_action('wp_ajax_restore_scripts', 'restore_scripts_handler');

function restore_scripts_handler() {

    if (!is_user_logged_in()) {
        wp_send_json_error();
    }

    $user_id = get_current_user_id();

    $ids = isset($_POST['ids'])
        ? json_decode(stripslashes($_POST['ids']), true)
        : [];

    foreach ($ids as $id) {

        $post = get_post((int)$id);

        if (!$post || $post->post_type !== 'script') continue;
        if ((int)$post->post_author !== $user_id) continue;

        // restore first
        wp_untrash_post($id);

        // FORCE VISIBILITY
        wp_update_post([
            'ID'          => $id,
            'post_status' => 'publish'
        ]);
    }

    wp_send_json_success();
}

function remove_script_from_all_bookmarks($script_id) {

    $users = get_users();

    foreach ($users as $user) {

        $bookmarks = get_user_meta($user->ID, 'saved_bookmarks', true);
        if (!is_array($bookmarks)) continue;

        $bookmarks = array_filter($bookmarks, function ($item) use ($script_id) {
            return !(
                isset($item['id'], $item['type']) &&
                (int)$item['id'] === (int)$script_id &&
                $item['type'] === 'script'
            );
        });

        update_user_meta($user->ID, 'saved_bookmarks', array_values($bookmarks));
    }
}

