add_action('pre_get_posts', function($query) {

    if (is_admin() || !$query->is_main_query()) return;

    if (
        is_post_type_archive('knowledge') ||
        is_tax('knowledge-category') ||
        is_tax('knowledge-subcategory')
    ) {

        $query->set('meta_query', [
            'relation' => 'OR',
            'relevance_clause' => [
                'key'     => 'relevance_score',
                'compare' => 'EXISTS',
                'type'    => 'NUMERIC',
            ],
            'no_relevance_clause' => [
                'key'     => 'relevance_score',
                'compare' => 'NOT EXISTS',
            ]
        ]);

        $query->set('orderby', [
            'relevance_clause' => 'DESC',
            'date' => 'DESC'
        ]);
    }
});

