add_action('wp_ajax_add_content_to_script', function () {

    if (!is_user_logged_in()) {
        wp_send_json_error('Not logged in');
    }

    $user_id    = get_current_user_id();
    $script_id  = intval($_POST['script_id'] ?? 0);
    $content_id = intval($_POST['content_id'] ?? 0);

    if (!$script_id || !$content_id) {
        wp_send_json_error('Missing data');
    }

    // 🚨 SECURITY CHECK: must be YOUR script
    $post = get_post($script_id);

    if (!$post || $post->post_type !== 'script') {
        wp_send_json_error('Invalid script');
    }

    if ((int)$post->post_author !== $user_id) {
        wp_send_json_error('Not your script');
    }

    // Load items
    $items = get_post_meta($script_id, 'script_items', true);
    if (!is_array($items)) $items = [];

    if (!in_array($content_id, $items)) {
        $items[] = $content_id;
        update_post_meta($script_id, 'script_items', $items);
    }

    wp_send_json_success(['message' => 'Added to script']);
});


add_action('wp_ajax_remove_content_from_script', function () {

    if (!is_user_logged_in()) {
        wp_send_json_error('Not logged in');
    }

    $user_id    = get_current_user_id();
    $script_id  = intval($_POST['script_id'] ?? 0);
    $content_id = intval($_POST['content_id'] ?? 0);

    if (!$script_id || !$content_id) {
        wp_send_json_error('Missing data');
    }

    $post = get_post($script_id);

    if (!$post || (int)$post->post_author !== $user_id) {
        wp_send_json_error('Not allowed');
    }

    $items = get_post_meta($script_id, 'script_items', true);
    if (!is_array($items)) $items = [];

    $items = array_values(array_filter($items, function ($id) use ($content_id) {
        return intval($id) !== $content_id;
    }));

    update_post_meta($script_id, 'script_items', $items);

    wp_send_json_success(['message' => 'Removed']);
});

function is_content_in_script($script_id, $content_id) {

    $items = get_post_meta($script_id, 'script_items', true);

    if (!is_array($items)) {
        return false;
    }

    return in_array($content_id, $items);
}

