            el.innerHTML = `<strong>${script.title}</strong>`;

            el.onclick = async () => {

                await addToScript(script.id, selectedContentId);
                closeScriptModal();

                Swal.fire({
                    icon: "success",
                    title: "Added!",
                    text: "Content added to script"
                });
            };

            list.appendChild(el);
        });
    }

    /* =========================
       ADD TO SCRIPT
    ========================= */

    async function addToScript(scriptId, contentId) {

        const res = await fetch("<?php echo admin_url('admin-ajax.php'); ?>", {
            method: "POST",
            headers: {
                "Content-Type": "application/x-www-form-urlencoded"
            },
            body: new URLSearchParams({
                action: "add_content_to_script",
                script_id: scriptId,
                content_id: contentId
            })
        });

        return await res.json();
    }

    /* =========================
       MODAL CONTROLS
    ========================= */

    function openScriptModal() {

        const modal = document.getElementById("addToScriptModal");
        modal.style.display = "flex";
        modal.classList.remove("hidden");
    }

    function closeScriptModal() {

        const modal = document.getElementById("addToScriptModal");
        modal.style.display = "none";
        modal.classList.add("hidden");
    }

    document.addEventListener("click", function (e) {

        if (e.target.id === "closeScriptModal") closeScriptModal();
        if (e.target.id === "addToScriptModal") closeScriptModal();
    });

    /* =========================
       REMOVE FROM SCRIPT
    ========================= */

    document.addEventListener("click", async function(e){

        const btn = e.target.closest(".remove-from-script-btn");
        if (!btn) return;

        const contentId = btn.dataset.contentId;

        const scriptId = new URLSearchParams(window.location.search)
            .get("script_id");

        if (!scriptId || !contentId) return;

        const res = await fetch("/wp-admin/admin-ajax.php", {
            method: "POST",
            headers: {
                "Content-Type": "application/x-www-form-urlencoded"
            },
            body: new URLSearchParams({
                action: "remove_content_from_script",
                script_id: scriptId,
                content_id: contentId
            })
        });

        const data = await res.json();

        if (data.success) location.reload();
    });

    /* =========================
       DRAG & SAVE
    ========================= */

    function initSortable() {

        const container = document.getElementById("scriptItems");

        console.log("Sortable container:", container);

        if (!container) return;

        new Sortable(container, {
            animation: 150,
            handle: ".drag-handle",
            draggable: ".script-item-card",

            onEnd: function () {

                const scriptId = new URLSearchParams(window.location.search)
                    .get("script_id");

                const order = [...container.querySelectorAll(".script-item-card")]
                    .map(el => el.dataset.id);

                fetch("/wp-admin/admin-ajax.php", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/x-www-form-urlencoded"
                    },
                    body: new URLSearchParams({
                        action: "save_script_order",
                        script_id: scriptId,
                        order: JSON.stringify(order)
                    })
                });
            }
        });
    }

    initSortable();

});

</script>

<?php });

add_filter('use_block_editor_for_post_type', function ($use_block_editor, $post_type) {

    if ($post_type === 'script') {
        return false;
    }

    return $use_block_editor;

}, 10, 2);

add_action('wp_head', function () {

    if (is_page('create-script') || isset($_GET['script_id'])) {
        acf_form_head();
    }

}, 1);

add_action('wp_ajax_save_script_order', function () {

    if (!is_user_logged_in()) {
        wp_send_json_error('Not logged in');
    }

    $script_id = intval($_POST['script_id'] ?? 0);
    $order = json_decode(stripslashes($_POST['order'] ?? ''), true);

    if (!$script_id || !is_array($order)) {
        wp_send_json_error('Missing data');
    }

    $order = array_map('intval', $order);

    // IMPORTANT: update ACF field properly
    update_field('script_items', $order, $script_id);

    wp_send_json_success([
        'message' => 'Order saved',
        'order' => $order
    ]);
});
